 {"id":"brenner_bot-399m","title":"Integration Tests: Storage Layer Real File System","description":"# Integration Tests: Storage Layer

## Current State
Storage adapters tested with in-memory fixtures only:
- `anomaly-storage.ts`
- `hypothesis-storage.ts`
- `assumption-storage.ts`
- `critique-storage.ts`
- `test-storage.ts`
- `program-storage.ts`
- `intervention-storage.ts`

## Gap
No tests for:
- Actual file system persistence
- Concurrent access patterns
- File corruption recovery
- Large dataset performance
- Index rebuild scenarios

## Goal
Add integration tests that use real temporary directories to verify actual file I/O.

## Test Scenarios

### 1. File Persistence Tests
```typescript
describe("Storage Layer Integration", () => {
  let tempDir: string;

  beforeEach(async () => {
    tempDir = await fs.mkdtemp(path.join(os.tmpdir(), "brenner-test-"));
    process.env.RESEARCH_DIR = tempDir;
  });

  afterEach(async () => {
    await fs.rm(tempDir, { recursive: true, force: true });
  });

  test("hypothesis persists to JSON file and survives reload", async () => {
    const storage = new HypothesisStorage(tempDir);

    await storage.save("SESSION-001", {
      id: "H-SESSION-001-001",
      name: "Test Hypothesis",
      claim: "...",
      mechanism: "..."
    });

    // Verify file exists
    const filePath = path.join(tempDir, "sessions", "SESSION-001", "hypotheses.json");
    expect(await fs.access(filePath).then(() => true).catch(() => false)).toBe(true);

    // Create new storage instance (simulates process restart)
    const reloadedStorage = new HypothesisStorage(tempDir);
    const hypothesis = await reloadedStorage.get("SESSION-001", "H-SESSION-001-001");
    expect(hypothesis?.name).toBe("Test Hypothesis");
  });
});
```

### 2. Concurrent Access Tests
```typescript
test("handles concurrent writes without data loss", async () => {
  const storage = new HypothesisStorage(tempDir);

  // Simulate concurrent writes
  const writes = Array.from({ length: 10 }, (_, i) => 
    storage.save("SESSION-001", {
      id: `H-SESSION-001-${String(i).padStart(3, "0")}`,
      name: `Hypothesis ${i}`,
      claim: "...",
      mechanism: "..."
    })
  );

  await Promise.all(writes);

  // Verify all written
  const all = await storage.list("SESSION-001");
  expect(all.length).toBe(10);
});
```

### 3. Index Rebuild Tests
```typescript
test("rebuilds index from corrupted state", async () => {
  const storage = new ProgramStorage(tempDir);

  // Create some programs
  await storage.save({ id: "PROG-001", name: "Test" });
  await storage.save({ id: "PROG-002", name: "Test 2" });

  // Corrupt the index file
  const indexPath = path.join(tempDir, "programs", "program-index.json");
  await fs.writeFile(indexPath, "CORRUPTED");

  // Create new instance - should rebuild
  const newStorage = new ProgramStorage(tempDir);
  const programs = await newStorage.list();

  expect(programs.length).toBe(2);
});
```

### 4. Large Dataset Performance
```typescript
test("handles 1000 hypotheses without timeout", async () => {
  const storage = new HypothesisStorage(tempDir);

  const start = performance.now();

  for (let i = 0; i < 1000; i++) {
    await storage.save("SESSION-001", {
      id: `H-SESSION-001-${String(i).padStart(3, "0")}`,
      name: `Hypothesis ${i}`,
      claim: "A".repeat(500),
      mechanism: "B".repeat(500)
    });
  }

  const writeTime = performance.now() - start;
  expect(writeTime).toBeLessThan(5000); // 5s max

  const readStart = performance.now();
  const all = await storage.list("SESSION-001");
  const readTime = performance.now() - readStart;

  expect(all.length).toBe(1000);
  expect(readTime).toBeLessThan(1000); // 1s max
});
```

